B.a3e=s(["Keep the fridge at or below 40\xb0F (4\xb0C).","Store raw meat on the bottom shelf so drips can't reach other food.","Use airtight containers for leftovers.","Label leftovers with the preparation date."],t.s)
B.Wc=new A.cF(B.a3e)
B.WD=new A.cs("Pantry tips")
B.a3j=s(["Store dry and canned goods in a cool, dry spot.","Keep opened dry goods in sealed containers \u2014 moisture is the enemy.","Use First In, First Out: place new stock behind older stock."],t.s)
B.VR=new A.cF(B.a3j)
B.a2d=s([B.WN,B.Wc,B.WD,B.VR],t.F)
B.Xq=new A.er("fridge-pantry","\ud83e\uddca","Fridge & pantry storage","Temperatures, shelf order, and keeping dry goods dry.",B.a2d)
B.Xk=new A.fE("Freezing slows spoilage dramatically and can rescue food you know you won't finish in time. The only real limit is quality degradation \u2014 freezer burn and texture loss.")
B.WS=new A.cs("Best practices")
B.a_Y=s(["Freeze food before it spoils, not after.","Use freezer-safe airtight packaging.","Remove as much air as possible (press flat, vacuum seal if you have one).","Label every package with the freeze date."],t.s)
B.W2=new A.cF(B.a_Y)
B.WE=new A.cs("Typical freezer storage times")
B.a64=s(["Meat: 6\u201312 months.","Cooked meals: 2\u20133 months.","Fruits and vegetables: 8\u201312 months.","Bread: 2\u20133 months."],t.s)
B.VY=new A.cF(B.a64)
B.WA=new A.f3("\u2705","Frozen food stays technically safe indefinitely \u2014 but quality degrades, so rotate the freezer too.")
B.a5v=s([B.Xk,B.WS,B.W2,B.WE,B.VY,B.WA],t.F)
B.Xp=new A.er("freezing","\u2744\ufe0f","Freezing food safely","What to freeze, how to package, how long it keeps.",B.a5v)
B.WK=new A.cs("The numbers")
B.a_q=s(["About one third of all food produced globally is wasted.","Food waste is a major contributor to greenhouse-gas emissions.","Households are among the largest single sources of food waste."],t.s)
B.W0=new A.cF(B.a_q)
B.uI=new A.cs("SDG 12.3")
B.Xf=new A.fE("UN Sustainable Development Goal 12.3 aims to halve global food waste per capita by 2030 \u2014 a target that the household tier needs to hit to succeed.")
B.X2=new A.cs("What you can do")
B.XO=s(["Learn how to read food labels so you don't discard good food.","Store food properly (see the fridge & pantry topic).","Freeze food before it spoils.","Use leftovers creatively \u2014 soups, stir-fries, frittatas.","Buy only what you need and shop more frequently if you can."],t.s)
B.W4=new A.cF(B.XO)
B.Wu=new A.f3("\ud83c\udf0d","Small household changes compound into meaningful system-level impact.")
B.Zz=s([B.WK,B.W0,B.uI,B.Xf,B.X2,B.W4,B.Wu],t.F)
B.XC=new A.er("reducing-waste","\u267b\ufe0f","Reducing food waste & SDG 12.3","Why it matters, and what UN Goal 12.3 asks of households.",B.Zz)
B.Xj=new A.fE("These are the default conventions you'll see in US grocery stores and home kitchens. Knowing them helps you read labels and store things correctly.")
B.uH=new A.cs("Storage defaults")
B.a2R=s(["Eggs: washed at the supplier \u2014 must be refrigerated.","Milk: pasteurized, refrigerated, 7\u201314 days after opening.","Bread: often refrigerated, plastic-wrapped.","Hard cheese: any mold treated as spoilage.","Potatoes and tomatoes: often refrigerated by default.","Shopping cadence: large, infrequent trips."],t.s)
B.VW=new A.cF(B.a2R)
B.uJ=new A.cs("Date labels")
B.a60=s(['"Best By" = quality, not safety. Almost always still safe past it.','"Use By" usually means quality too \u2014 the only true exception is infant formula.',"Dates drive a lot of household discards. Trust your senses first."],t.s)
B.VZ=new A.cF(B.a60)
B.uE=new A.cs("Cultural defaults")
B.a66=s(['"When in doubt, throw it out" is the common reflex.',"Low tolerance for any mold.","The fridge tends to be the default answer for storage.","Plastic, airtight packaging is the norm."],t.s)
B.W8=new A.cF(B.a66)
B.Wt=new A.f3("\u2705","Pause before tossing on the printed date \u2014 for most items it's a quality marker, not a safety one.")
B.a2H=s([B.Xj,B.uH,B.VW,B.uJ,B.VZ,B.uE,B.W8,B.Wt],t.F)
B.XD=new A.er("local-habits-us","\ud83c\uddfa\ud83c\uddf8","Food habits in the US","How storage, labels, and shopping work in the US.",B.a2H)
B.Xe=new A.fE("These are the default conventions you'll see in Swiss grocery stores and home kitchens. They lean toward smaller, more frequent shops and selective refrigeration.")
B.a0S=s(["Eggs: unwashed; keep at room temperature for up to ~21 days.","UHT milk is common \u2014 shelf-stable until opened.","Bread: never refrigerated; store in paper or cloth.","Hard cheese: trim small mold off, keep breathable.","Potatoes: cool, dark, ventilated. Tomatoes: room temperature.","Shopping cadence: smaller, more frequent trips."],t.s)
B.W9=new A.cF(B.a0S)
B.a6l=s(['"Mindestens haltbar bis" / "\xc0 consommer de pr\xe9f\xe9rence avant" = quality indicator. Likely fine after the date.','"Zu verbrauchen bis" / "\xc0 consommer jusqu\'au" is a strict safety date \u2014 illegal for shops to sell past it.',"Sensory checks are encouraged \u2014 look, smell, taste-of-doubt."],t.s)
B.Wg=new A.cF(B.a6l)
B.a1d=s(['"Assess the condition before discarding" is the common reflex.',"Mold tolerance depends on the product (cured meats, hard cheese).","Selective refrigeration \u2014 not everything goes in the fridge.","Paper, breathable, minimal packaging is the norm."],t.s)
B.VN=new A.cF(B.a1d)
B.Wo=new A.f3("\u2705",'Use your senses first; the printed date is a guideline, not a hard cutoff (except "Zu verbrauchen bis" / "\xc0 consommer jusqu\'au").')
