B.X6=new A.fE("L'Obiettivo 12.3 dell'Agenda ONU punta a dimezzare lo spreco alimentare pro capite entro il 2030 \u2014 un traguardo raggiungibile solo con il contributo delle famiglie.")
B.WW=new A.cs("Cosa puoi fare")
